                                         val[3][1].delete( :score )  ## note - remove/delete  flag
                                           { et: val[1][1][:score] }
                                     elsif val[3][1][:score] && 
                                           val[3][1][:score]=='ht' ## check ht flag present?
                                         val[3][1].delete( :score ) ## note - remove/delete flag
                                           { ht: val[1][1][:score] }      
                                     elsif val[3][1][:score] && 
                                           val[3][1][:score]=='ft'  ## check ft flag present?
                                         val[3][1].delete( :score )  ## note - remove/delete flag
                                           { ft: val[1][1][:score] }
                                     else   ## assume full-time (ft)
                                            { ft: val[1][1][:score] }
                                     end 

                           result = {  team1: val[0],
                                      team2: val[2],
                                      score: score.merge( val[3][1] )
                                    }                                    

    result
  end
